async (params, browser) => {
  // Open Telegram Web
  await browser.open('https://web.telegram.org/k/')

  // Wait for Telegram to load
  await browser.waitForSelector('.input-search input, .chatlist-chat, .chat-list', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Focus search input
  const focus_search = await browser.evaluate(`const searchInput = document.querySelector('.input-search input') || document.querySelector('input[type="text"]'); if (searchInput) { searchInput.focus(); searchInput.click(); } else { const searchArea = document.querySelector('.input-search'); if (searchArea) searchArea.click(); } return { focused: true }`)

  await browser.wait(500)

  // Type search query
  const type_query = await browser.evaluate(`const searchInput = document.querySelector('.input-search input') || document.querySelector('input[type="text"]'); if (searchInput) { searchInput.focus(); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.query); searchInput.dispatchEvent(new Event('input', { bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const chatItems = document.querySelectorAll('.chatlist-chat, .search-group .chatlist-chat, .chat-list .ListItem, .search-super-content .row'); for (let i = 0; i < Math.min(chatItems.length, 15); i++) { const el = chatItems[i]; const nameEl = el.querySelector('.peer-title, .user-title, .dialog-title'); const previewEl = el.querySelector('.dialog-subtitle, .message-preview, .last-message'); const badgeEl = el.querySelector('.dialog-subtitle-badge, .badge, .unread-count'); results.push({ name: nameEl ? nameEl.textContent.trim() : '', preview: previewEl ? previewEl.textContent.trim() : '', has_unread: badgeEl ? true : false }); } return { result_count: results.length, query: params.query, results: results }`)

  return search_results
}
